{
  "meta": {
    "created_at": "2026-04-16T08:00:00+08:00",
    "author": "metaclaw_agent",
    "status": "ready",
    "schema_version": "1.0",
    "notes": "Test fixtures for /projects and /tasks endpoints. Includes sample request bodies and expected responses (happy path + a few common errors)."
  },
  "projects": {
    "create": {
      "endpoint": "/projects",
      "method": "POST",
      "request": {
        "name": "Website Redesign",
        "key": "WEBRED",
        "description": "Redesign the marketing website and landing pages.",
        "owner_user_id": "usr_1001",
        "visibility": "private",
        "start_date": "2026-04-15",
        "due_date": "2026-05-31",
        "tags": [
          "marketing",
          "web"
        ]
      },
      "expected_response": {
        "status_code": 201,
        "body": {
          "id": "proj_2001",
          "name": "Website Redesign",
          "key": "WEBRED",
          "description": "Redesign the marketing website and landing pages.",
          "owner_user_id": "usr_1001",
          "visibility": "private",
          "start_date": "2026-04-15",
          "due_date": "2026-05-31",
          "tags": [
            "marketing",
            "web"
          ],
          "status": "active",
          "created_at": "2026-04-16T09:30:00+08:00",
          "updated_at": "2026-04-16T09:30:00+08:00"
        }
      }
    },
    "get": {
      "endpoint": "/projects/{project_id}",
      "method": "GET",
      "request": {
        "path_params": {
          "project_id": "proj_2001"
        }
      },
      "expected_response": {
        "status_code": 200,
        "body": {
          "id": "proj_2001",
          "name": "Website Redesign",
          "key": "WEBRED",
          "description": "Redesign the marketing website and landing pages.",
          "owner_user_id": "usr_1001",
          "visibility": "private",
          "start_date": "2026-04-15",
          "due_date": "2026-05-31",
          "tags": [
            "marketing",
            "web"
          ],
          "status": "active",
          "created_at": "2026-04-16T09:30:00+08:00",
          "updated_at": "2026-04-16T09:35:00+08:00"
        }
      }
    },
    "create_invalid": {
      "endpoint": "/projects",
      "method": "POST",
      "request": {
        "name": "",
        "key": "TOO_LONG_PROJECT_KEY",
        "owner_user_id": "",
        "visibility": "secret"
      },
      "expected_response": {
        "status_code": 400,
        "body": {
          "error": {
            "code": "VALIDATION_ERROR",
            "message": "Request validation failed",
            "details": [
              {
                "field": "name",
                "issue": "must be non-empty"
              },
              {
                "field": "key",
                "issue": "invalid format or length"
              },
              {
                "field": "owner_user_id",
                "issue": "must be non-empty"
              },
              {
                "field": "visibility",
                "issue": "must be one of [private, org, public]"
              }
            ]
          }
        }
      }
    }
  },
  "tasks": {
    "create": {
      "endpoint": "/tasks",
      "method": "POST",
      "request": {
        "project_id": "proj_2001",
        "title": "Draft new homepage copy",
        "description": "Write new copy for hero section and key value props.",
        "assignee_user_id": "usr_1002",
        "priority": "high",
        "status": "todo",
        "due_at": "2026-04-20T18:00:00+08:00",
        "estimate_minutes": 180,
        "labels": [
          "copy",
          "homepage"
        ]
      },
      "expected_response": {
        "status_code": 201,
        "body": {
          "id": "task_3001",
          "project_id": "proj_2001",
          "title": "Draft new homepage copy",
          "description": "Write new copy for hero section and key value props.",
          "assignee_user_id": "usr_1002",
          "priority": "high",
          "status": "todo",
          "due_at": "2026-04-20T18:00:00+08:00",
          "estimate_minutes": 180,
          "labels": [
            "copy",
            "homepage"
          ],
          "created_at": "2026-04-16T09:45:00+08:00",
          "updated_at": "2026-04-16T09:45:00+08:00"
        }
      }
    },
    "get": {
      "endpoint": "/tasks/{task_id}",
      "method": "GET",
      "request": {
        "path_params": {
          "task_id": "task_3001"
        }
      },
      "expected_response": {
        "status_code": 200,
        "body": {
          "id": "task_3001",
          "project_id": "proj_2001",
          "title": "Draft new homepage copy",
          "description": "Write new copy for hero section and key value props.",
          "assignee_user_id": "usr_1002",
          "priority": "high",
          "status": "in_progress",
          "due_at": "2026-04-20T18:00:00+08:00",
          "estimate_minutes": 180,
          "labels": [
            "copy",
            "homepage"
          ],
          "created_at": "2026-04-16T09:45:00+08:00",
          "updated_at": "2026-04-16T10:10:00+08:00"
        }
      }
    },
    "create_invalid": {
      "endpoint": "/tasks",
      "method": "POST",
      "request": {
        "project_id": "proj_missing",
        "title": "",
        "priority": "urgent",
        "status": "blocked",
        "due_at": "not-a-timestamp"
      },
      "expected_response": {
        "status_code": 400,
        "body": {
          "error": {
            "code": "VALIDATION_ERROR",
            "message": "Request validation failed",
            "details": [
              {
                "field": "title",
                "issue": "must be non-empty"
              },
              {
                "field": "priority",
                "issue": "must be one of [low, medium, high]"
              },
              {
                "field": "status",
                "issue": "must be one of [todo, in_progress, done]"
              },
              {
                "field": "due_at",
                "issue": "must be ISO 8601 timestamp"
              }
            ]
          }
        }
      }
    },
    "get_not_found": {
      "endpoint": "/tasks/{task_id}",
      "method": "GET",
      "request": {
        "path_params": {
          "task_id": "task_9999"
        }
      },
      "expected_response": {
        "status_code": 404,
        "body": {
          "error": {
            "code": "NOT_FOUND",
            "message": "Task not found"
          }
        }
      }
    }
  }
}
